（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
